#include <bits/stdc++.h>
using namespace std;
char a[105][105];
int b[105][105];
int main() {
	int n,m;
	cin>>n>>m;
	int dx[8]= {1,0,-1,0,-1,1,1,-1};
	int dy[8]= {0,1,0,-1,-1,-1,1,1};
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=m; j++) {
			cin>>a[i][j];
			if(a[i][j]=='*') {
				for(int k=0; k<8; k++) {
					int nx=i+dx[k],ny=j+dy[k];
					if(nx>=1&&nx<=n&&ny>=1&&ny<=n) {
						b[nx][ny]++;
					}
				}
			}
		}
	}
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=m; j++) {
			if(a[i][j]=='*') {
				cout<<'*';
			} else {
				cout<<b[i][j];
			}
		}
		cout<<"\n";
	}
	return 0;
}
